import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Test for block comments inside single-line blocks.
 * See: https://github.com/pinterest/ktlint/issues/...
 */
class CommentWrappingRuleBlockTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a block comment inside a single-line block then do not report a violation`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a block comment inside a multi-line block then do not report a violation`() {
        val code =
            """
            val foo = {
                /* no-op */
            }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a block comment after a code element on the same line outside a block then report a violation`() {
        val code =
            """
            val foo = "foo" /* comment */
            """.trimIndent()
        commentWrappingRuleAssertThat(code)
            .hasLintViolation(1, 17, "A single line block comment after a code element on the same line must be replaced with an EOL comment")
    }

    @Test
    fun `Given multiple block comments inside single-line blocks then do not report violations`() {
        val code =
            """
            val foo = { /* comment 1 */ }
            val bar = { /* comment 2 */ }
            val baz = { /* comment 3 */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }
}"}

